class FenwickTree {
    private tree: number[];
    private size: number;

    constructor(n: number) {
        this.size = n;
        this.tree = new Array(n + 2).fill(0);
    }

    update(idx: number, delta: number): void {
        idx += 1;
        while (idx <= this.size) {
            this.tree[idx] += delta;
            idx += idx & -idx;
        }
    }

    query(idx: number): number {
        idx += 1;
        let res = 0;
        while (idx > 0) {
            res += this.tree[idx];
            idx -= idx & -idx;
        }
        return res;
    }

    rangeQuery(l: number, r: number): number {
        return this.query(r) - this.query(l - 1);
    }
}

function solve(nums: number[], queries: number[][]): number[] {
    function popcount(x: number): number {
        let count = 0;
        while (x > 0) {
            x &= x - 1;
            count++;
        }
        return count;
    }

    function computeDepth(x: number): number {
        let depth = 0;
        let current = x;
        while (current !== 1) {
            current = popcount(current);
            depth++;
        }
        return depth;
    }

    const n = nums.length;
    const ft = new Array(5).fill(0).map(() => new FenwickTree(n));

    for (let i = 0; i < n; i++) {
        const d = computeDepth(nums[i]);
        if (d <= 4) {
            ft[d].update(i, 1);
        }
    }

    const answer: number[] = [];

    for (const q of queries) {
        if (q[0] === 1) {
            const l = q[1];
            const r = q[2];
            const k = q[3];
            if (k > 4) {
                answer.push(0);
                continue;
            }
            const res = ft[k].rangeQuery(l, r);
            answer.push(res);
        } else {
            const idx = q[1];
            const val = q[2];
            const oldD = computeDepth(nums[idx]);
            const newD = computeDepth(val);
            if (oldD <= 4) {
                ft[oldD].update(idx, -1);
            }
            nums[idx] = val;
            if (newD <= 4) {
                ft[newD].update(idx, 1);
            }
        }
    }

    return answer;
}
